# solver settings
solvers
{
    buoyantFoam
    {
        // Time integration settings
        transientScheme   Euler;
        // Pressure-velocity coupling
        pressureControl   nonInlet;
        // Time step settings
        nCorrectors       1;
        nNonOrthogonalCorrectors 0;
        // Convergence criteria
        maxIterations     10;
        tolerance         1e-6;
        relativeTolerance 0.1;
        // Solution output control
        writeControl      timeStep;
        writeInterval     1;
    }
}

# SIMPLE algorithm settings
SIMPLE
{
    // Pressure-velocity coupling
    transientSurfaceInterpolationSchemes
    {
        default linear;
    }
    // Convergence settings
    nNonOrthogonalCorrectors 0;
    pRefCell        0;
    pRefValue       0;
    // Relaxation factors
    relaxationFactors
    {
        p   0.3;
        u   0.7;
        v   0.7;
        w   0.7;
    }
}

# Solution output control
solution
{
    // Output fields to write
    fields
    {
        // Write velocity, pressure, temperature, and turbulence variables
        U           yes;
        p           yes;
        T           yes;
        k           yes;
        nut         yes;
        // Write at specified intervals
        writeControl timeStep;
        writeInterval 1;
    }
    // Output format
    format        raw;
    // Binary output
    binary        yes;
}

