ddtSchemes {
    default scheme;
    ddt(U) scheme;
    ddt(p) scheme;
    ddt(T) scheme;
}

gradSchemes {
    default gradSchemes;
    grad(T) Gauss linear;
    grad(p) Gauss linear;
