# Time: 0 to 1000 s, deltaT=1 s, writeInterval=50 s
# Boundary conditions: hot wall at 305 K, cold wall at 300 K

dimensions 2 0 1 0 0 0 0;
internalField uniform (0 0 0);
boundaryField
{
    inlet
    {
        type fixedValue;
        value uniform (0 0 0);
    }
    outlet
    {
        type zeroGradient;
    }
    hotWall
    {
        type fixedValue;
        value uniform (0 0 0);
    }
    coldWall
    {
        type fixedValue;
        value uniform (0 0 0);
    }
    top
    {
        type zeroGradient;
    }
    bottom
    {
        type zeroGradient;
    }
}

# Generated 0/T file for Bernard Cells simulation
# Solver: buoyantFoam
# Case: 3D heat transfer in Bernard Cells
# Domain: 9 m x 1 m x 2 m
# Time: 0 to 1000 s, deltaT=1 s, writeInterval=50 s
# Boundary conditions: hot wall at 305 K, cold wall at 300 K

dimensions 0 0 0 1 0 0 0;
internalField uniform 300;
boundaryField
{
    inlet
    {
        type fixedValue;
        value uniform 300;
    }
    outlet
    {
        type zeroGradient;
    }
    hotWall
    {
        type fixedValue;
        value uniform 305;
    }
    coldWall
    {
        type fixedValue;
        value uniform 300;
    }
    top
    {
        type zeroGradient;
    }
    bottom
    {
        type zeroGradient;
    }
}

